mapper.select:
SELECT COUNT(*)
  FROM tb_user_coupon
 WHERE user_id    = #{userId}
   AND coupon_id  = #{couponId}
   AND is_deleted = 0

SELECT uc.user_coupon_id, uc.user_id, uc.coupon_id, uc.coupon_code, uc.status, uc.used_at, uc.created_at, co.coupon_name, co.benefit, co.condition_text, co.expire_date, co.store_id, s.store_name, s.category, s.region_id FROM tb_user_coupon uc JOIN tb_coupon co ON uc.coupon_id = co.coupon_id JOIN tb_store s ON co.store_id = s.store_id WHERE uc.user_id = #{userId} AND uc.is_deleted = 0
AND uc.status = #{status}
AND s.category = #{category}
AND s.region_id = #{regionId}
AND (co.coupon_name LIKE CONCAT('%', #{keyword}, '%') OR s.store_name LIKE CONCAT('%', #{keyword}, '%') OR co.benefit LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY uc.created_at DESC
